import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { Link, useNavigate } from "react-router-dom";
import { Table, Button, Tag, Tooltip, Badge, Input, Select } from "antd";
import { getAdminB2bProducts } from "../../features/b2b/b2bSlice";
import { getSocket } from "../../socket";
import {
  Package,
  Plus,
  Search,
  Eye,
  Edit,
  Layers,
  AlertTriangle,
  Building2,
  RefreshCw,
} from "lucide-react";

const B2bProductList = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { b2bProducts, b2bProductsMeta, isLoading } = useSelector((state) => state.b2b);

  const [search, setSearch] = useState("");
  const [categoryFilter, setCategoryFilter] = useState("");
  const [statusFilter, setStatusFilter] = useState("");

  const fetchProducts = () => {
    const params = {};
    if (search) params.search = search;
    if (categoryFilter) params.b2bCategory = categoryFilter;
    if (statusFilter) params.status = statusFilter;
    params.limit = 200; // load all for local stat counting
    dispatch(getAdminB2bProducts(params));
  };

  useEffect(() => {
    fetchProducts();
    // eslint-disable-next-line
  }, [dispatch, search, categoryFilter, statusFilter]);

  // Real-time product updates
  useEffect(() => {
    const socket = getSocket();
    if (!socket) return;
    const refresh = () => fetchProducts();
    socket.on("product:updated", refresh);
    return () => socket.off("product:updated", refresh);
    // eslint-disable-next-line
  }, [dispatch, search, categoryFilter, statusFilter]);

  const b2bCategories = [
    { value: "PHARMACEUTICALS", label: "Pharmaceuticals" },
    { value: "SURGICAL_INSTRUMENTS", label: "Surgical Instruments" },
    { value: "LABORATORY_REAGENTS", label: "Laboratory Reagents" },
    { value: "RAPID_DIAGNOSTIC_TESTS", label: "Rapid Diagnostic Tests" },
    { value: "ICU_CRITICAL_CARE_EQUIPMENT", label: "ICU Critical Care" },
    { value: "DIAGNOSTIC_EQUIPMENT", label: "Diagnostic Equipment" },
    { value: "MEDICAL_CONSUMABLES", label: "Medical Consumables" },
    { value: "PPE_INFECTION_CONTROL", label: "PPE & Infection Control" },
    { value: "HOSPITAL_FURNITURE", label: "Hospital Furniture" },
    { value: "PHARMACY_SUPPLIES", label: "Pharmacy Supplies" },
  ];

  const products = b2bProducts || [];

  const columns = [
    {
      title: "Product",
      dataIndex: "title",
      render: (text, record) => (
        <div className="flex items-center gap-3">
          <div className="w-11 h-11 rounded-xl bg-slate-50 border border-slate-100 flex items-center justify-center overflow-hidden flex-shrink-0">
            {(record.images?.[0] || record.colors?.[0]?.images?.[0]) ? (
              <img
                src={
                  record.images?.[0]?.secure_url ||
                  record.images?.[0]?.url ||
                  (typeof record.images?.[0] === "string" ? record.images[0] : "") ||
                  record.colors?.[0]?.images?.[0]?.secure_url ||
                  record.colors?.[0]?.images?.[0]?.url ||
                  (typeof record.colors?.[0]?.images?.[0] === "string" ? record.colors[0].images[0] : "")
                }
                alt={text}
                className="w-full h-full object-cover"
              />
            ) : (
              <Package size={18} className="text-slate-300" />
            )}
          </div>
          <div>
            <span className="font-bold text-slate-900 block text-[14px]">{text}</span>
            {record.genericName && (
              <span className="text-[11px] text-slate-400 italic block">{record.genericName}</span>
            )}
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
              SKU: {record.sku || "N/A"}
            </span>
          </div>
        </div>
      ),
    },
    {
      title: "B2B Category",
      dataIndex: "b2bCategory",
      render: (cat) => (
        <Tag color="blue" className="font-bold uppercase text-[10px]">
          {(cat || "").replace(/_/g, " ")}
        </Tag>
      ),
    },
    {
      title: "Wholesale Price",
      dataIndex: "wholesalePrice",
      render: (price) => (
        <span className="font-black text-slate-900 text-[14px]">
          {parseFloat(price || 0).toLocaleString()}{" "}
          <span className="text-[10px] text-slate-400">ETB</span>
        </span>
      ),
      sorter: (a, b) => (a.wholesalePrice || 0) - (b.wholesalePrice || 0),
    },
    {
      title: "MOQ / Case",
      render: (_, record) => (
        <div className="flex flex-col text-xs font-bold text-slate-600">
          <span>MOQ: {record.minimumOrderQuantity || 1}</span>
          {record.caseQuantity > 1 && (
            <span className="text-blue-600">Case: {record.caseQuantity}</span>
          )}
        </div>
      ),
    },
    {
      title: "Stock",
      dataIndex: "quantity",
      render: (qty, record) => (
        <div className="flex items-center gap-2">
          <Badge
            status={
              qty <= 0
                ? "error"
                : qty <= (record.reorderLevel || 0)
                ? "warning"
                : "success"
            }
          />
          <span className="font-bold text-slate-700 text-sm">{qty ?? "—"}</span>
          {qty > 0 && qty <= (record.reorderLevel || 0) && (
            <Tooltip title="At or below reorder level">
              <AlertTriangle size={13} className="text-amber-500" />
            </Tooltip>
          )}
        </div>
      ),
      sorter: (a, b) => (a.quantity || 0) - (b.quantity || 0),
    },
    {
      title: "Status",
      dataIndex: "status",
      render: (status) => {
        const map = {
          approved: { color: "green", label: "Approved" },
          pending: { color: "orange", label: "Pending" },
          rejected: { color: "red", label: "Rejected" },
        };
        const { color, label } = map[status] || { color: "default", label: status };
        return (
          <Tag color={color} className="uppercase text-[10px] font-black">
            {label}
          </Tag>
        );
      },
    },
    {
      title: "Expiry",
      dataIndex: "expiryDate",
      render: (date) =>
        date ? (
          <span className={`text-xs font-bold ${new Date(date) < new Date() ? "text-red-500" : "text-slate-600"}`}>
            {new Date(date).toLocaleDateString()}
          </span>
        ) : (
          <span className="text-slate-400 text-xs">—</span>
        ),
    },
    {
      title: "Actions",
      render: (_, record) => (
        <div className="flex items-center gap-1.5">
          <Tooltip title="View">
            <Link to={`/admin/product/${record.id || record._id}`}>
              <Button
                type="text"
                icon={<Eye size={16} />}
                className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl w-9 h-9 flex items-center justify-center"
              />
            </Link>
          </Tooltip>
          <Tooltip title="Edit">
            <Button
              type="text"
              icon={<Edit size={16} />}
              onClick={() => navigate(`/admin/product/${record.id || record._id}`)}
              className="text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl w-9 h-9 flex items-center justify-center"
            />
          </Tooltip>
        </div>
      ),
    },
  ];

  const lowStockCount = products.filter(
    (p) => p.quantity > 0 && p.quantity <= (p.reorderLevel || 0)
  ).length;
  const outOfStockCount = products.filter((p) => p.quantity <= 0).length;
  const pendingCount = products.filter((p) => p.status === "pending").length;

  return (
    <div className="space-y-6 pb-12">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <Building2 size={18} className="text-blue-600" />
            <span className="text-[11px] font-black text-blue-600 uppercase tracking-[0.2em]">
              B2B Wholesale
            </span>
          </div>
          <h1 className="text-[28px] font-bold text-slate-900 tracking-tight">
            B2B Product Catalog
          </h1>
          <p className="text-[14px] text-slate-500 mt-1 font-medium">
            Only products with a B2B category enabled — these are what clients see at{" "}
            <code className="text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded text-[12px]">
              /b2b
            </code>
          </p>
        </div>
        <div className="flex items-center gap-3">
          <Button
            icon={<RefreshCw size={14} />}
            onClick={fetchProducts}
            className="h-10 rounded-xl border-slate-200 font-bold text-slate-600"
          >
            Refresh
          </Button>
          <Link
            to="/admin/product"
            className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-2xl font-black text-sm uppercase tracking-wider flex items-center gap-2 transition-colors shadow-lg shadow-blue-200"
          >
            <Plus size={16} /> Add B2B Product
          </Link>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        {[
          {
            label: "Total B2B Listings",
            value: b2bProductsMeta?.total ?? products.length,
            icon: Layers,
            color: "blue",
          },
          {
            label: "Low Stock",
            value: lowStockCount,
            icon: AlertTriangle,
            color: "amber",
          },
          {
            label: "Out of Stock",
            value: outOfStockCount,
            icon: Package,
            color: "red",
          },
          {
            label: "Pending Approval",
            value: pendingCount,
            icon: Package,
            color: "orange",
          },
        ].map(({ label, value, icon: Icon, color }) => (
          <div
            key={label}
            className="bg-white rounded-2xl border border-slate-100 p-4 shadow-sm flex items-center gap-3"
          >
            <div
              className={`w-10 h-10 rounded-xl flex items-center justify-center
                ${color === "blue" ? "bg-blue-50 text-blue-600" : ""}
                ${color === "amber" ? "bg-amber-50 text-amber-600" : ""}
                ${color === "red" ? "bg-red-50 text-red-600" : ""}
                ${color === "orange" ? "bg-orange-50 text-orange-600" : ""}
              `}
            >
              <Icon size={18} />
            </div>
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">
                {label}
              </p>
              <p className="text-xl font-black text-slate-900 mt-0.5">{value}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div className="bg-white rounded-2xl border border-slate-100 p-4 shadow-sm flex flex-col md:flex-row gap-3 items-stretch md:items-center">
        <div className="relative flex-1 md:max-w-xs">
          <Search
            className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"
            size={16}
          />
          <Input
            placeholder="Search title, SKU, generic..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9 h-10 rounded-xl border-slate-200 text-sm font-semibold"
          />
        </div>
        <Select
          value={categoryFilter || undefined}
          onChange={setCategoryFilter}
          placeholder="All B2B Categories"
          allowClear
          className="w-full md:w-52"
          style={{ height: 40 }}
        >
          {b2bCategories.map((c) => (
            <Select.Option key={c.value} value={c.value}>
              {c.label}
            </Select.Option>
          ))}
        </Select>
        <Select
          value={statusFilter || undefined}
          onChange={setStatusFilter}
          placeholder="All Statuses"
          allowClear
          className="w-full md:w-40"
          style={{ height: 40 }}
        >
          <Select.Option value="approved">Approved</Select.Option>
          <Select.Option value="pending">Pending</Select.Option>
          <Select.Option value="rejected">Rejected</Select.Option>
        </Select>
      </div>

      {/* Empty state hint when no products */}
      {!isLoading && products.length === 0 && (
        <div className="bg-amber-50 border border-amber-200 rounded-2xl p-5 flex items-start gap-4">
          <div className="w-10 h-10 bg-amber-500 text-white rounded-xl flex items-center justify-center shrink-0">
            <AlertTriangle size={18} />
          </div>
          <div>
            <p className="font-extrabold text-amber-900 text-[14px]">
              No B2B-enabled products found
            </p>
            <p className="text-amber-700 text-sm font-medium mt-1">
              To make a product appear in the B2B catalog (client{" "}
              <code className="bg-amber-100 px-1 rounded">/b2b</code>), go to{" "}
              <strong>Products → Edit product</strong> and enable the{" "}
              <strong>"🏭 List as B2B / Wholesale"</strong> toggle, then select a B2B category.
            </p>
          </div>
        </div>
      )}

      {/* Table */}
      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        <Table
          columns={columns}
          dataSource={products}
          loading={isLoading}
          rowKey={(record) => record.id || record._id}
          pagination={{
            pageSize: 20,
            showSizeChanger: false,
            showTotal: (total) => (
              <span className="text-[12px] font-bold text-slate-500">
                {total} B2B product{total !== 1 ? "s" : ""}
              </span>
            ),
          }}
          scroll={{ x: 900 }}
        />
      </div>

      <style>{`
        .ant-table-thead > tr > th {
          background: #fafbfc !important;
          font-weight: 800 !important;
          font-size: 11px !important;
          color: #64748b !important;
          text-transform: uppercase !important;
          letter-spacing: 0.08em !important;
          border-bottom: 2px solid #f1f5f9 !important;
        }
        .ant-table-tbody > tr > td {
          border-bottom: 1px solid #f8fafc !important;
        }
        .ant-table-tbody > tr:hover > td {
          background: #fafbfc !important;
        }
      `}</style>
    </div>
  );
};

export default B2bProductList;
